### Create Agent
# @name create_agent_route
POST {{host}}/v1/convai/agents/create?enable_versioning=true
xi-api-key: {{api_key}}
Content-Type: application/json
Accept: application/json

{
  "conversation_config": {
    "asr": {
      "keywords": [
        "hello",
        "world"
      ],
      "provider": "elevenlabs",
      "quality": "high",
      "user_input_audio_format": "pcm_16000"
    },
    "turn": {
      "interruption_ignore_terms": [],
      "mode": "turn",
      "retranscribe_on_turn_timeout": false,
      "silence_end_call_timeout": -1.0,
      "soft_timeout_config": {
        "message": "Hhmmmm...yeah.",
        "timeout_seconds": -1.0
      },
      "speculative_turn": false,
      "spelling_patience": "auto",
      "turn_eagerness": "normal",
      "turn_timeout": 7.0
    },
    "tts": {
      "agent_output_audio_format": "pcm_16000",
      "model_id": "eleven_turbo_v2",
      "optimize_streaming_latency": 3,
      "pronunciation_dictionary_locators": [],
      "similarity_boost": 0.8,
      "speed": 1.0,
      "stability": 0.5,
      "voice_id": "cjVigY5qzO86Huf0OWal"
    },
    "conversation": {
      "client_events": [
        "audio",
        "interruption"
      ],
      "max_duration_seconds": 600
    },
    "language_presets": {},
    "vad": {
      "background_voice_detection": false
    },
    "agent": {
      "disable_first_message_interruptions": false,
      "first_message": "Hello, how can I help you today?",
      "language": "en"
    }
  },
  "platform_settings": {
    "evaluation": {
      "criteria": []
    },
    "widget": {
      "custom_avatar_path": "https://example.com/avatar.png",
      "language_selector": false
    },
    "data_collection": {},
    "data_collection_scopes": {},
    "overrides": {
      "custom_llm_extra_body": true,
      "enable_conversation_initiation_client_data_from_webhook": true,
      "enable_starting_workflow_node_id_from_client": true
    },
    "workspace_overrides": {
      "conversation_initiation_client_data_webhook": {
        "request_headers": {
          "Content-Type": "application/json"
        },
        "url": "https://example.com/webhook"
      },
      "webhooks": {}
    },
    "testing": {
      "attached_tests": [
        {
          "environment": "staging",
          "test_id": "test_123",
          "workflow_node_id": "node_abc"
        },
        {
          "test_id": "test_456"
        }
      ],
      "referenced_tests_ids": [
        "test_123",
        "test_456"
      ]
    },
    "archived": false,
    "guardrails": {
      "version": "1",
      "focus": {},
      "prompt_injection": {},
      "content": {},
      "moderation": {},
      "custom": {}
    },
    "summary_language": "string",
    "auth": {
      "allowlist": [
        {
          "hostname": "https://example.com"
        }
      ],
      "enable_auth": true,
      "require_origin_header": true,
      "shareable_token": "1234567890"
    },
    "call_limits": {
      "agent_concurrency_limit": -1,
      "bursting_enabled": true,
      "daily_limit": 100000
    },
    "privacy": {
      "apply_to_existing_conversations": false,
      "delete_audio": false,
      "delete_transcript_and_pii": false,
      "record_voice": true,
      "retention_days": -1,
      "zero_retention_mode": false
    },
    "trust_context": "unknown",
    "analysis_llm": "gemini-2.5-flash"
  },
  "workflow": {
    "edges": {
      "entry_to_tool_a": {
        "forward_condition": {
          "condition": "Tool A condition"
        },
        "source": "entry_node",
        "target": "tool_node_a"
      },
      "start_to_entry": {
        "forward_condition": {},
        "source": "start_node",
        "target": "entry_node"
      },
      "tool_a_to_failure": {
        "forward_condition": {
          "successful": false
        },
        "source": "tool_node_a",
        "target": "failure_node"
      },
      "tool_a_to_tool_b": {
        "forward_condition": {
          "successful": true
        },
        "source": "tool_node_a",
        "target": "tool_node_b"
      },
      "tool_b_to_agent_transfer": {
        "forward_condition": {},
        "source": "tool_node_b",
        "target": "success_transfer"
      },
      "tool_b_to_conversation": {
        "forward_condition": {
          "condition": "Conversation condition"
        },
        "source": "tool_node_b",
        "target": "success_conversation"
      },
      "tool_b_to_end": {
        "forward_condition": {
          "condition": "End condition"
        },
        "source": "tool_node_b",
        "target": "success_end"
      },
      "tool_b_to_phone": {
        "forward_condition": {
          "expression": {
            "children": [
              {
                "name": "force_phone_transfer"
              },
              {
                "prompt": "Phone condition",
                "value_schema": {
                  "description": "Phone condition",
                  "type": "boolean"
                }
              },
              {
                "left": {
                  "name": "mode"
                },
                "right": {
                  "value": "dev"
                }
              }
            ]
          }
        },
        "source": "tool_node_b",
        "target": "success_phone"
      }
    },
    "nodes": {
      "entry_node": {
        "conversation_config": {},
        "edge_order": [
          "entry_to_tool_a"
        ],
        "label": "Entry"
      },
      "failure_node": {
        "conversation_config": {},
        "label": "Failure"
      },
      "start_node": {
        "edge_order": [
          "start_to_entry"
        ]
      },
      "success_conversation": {
        "conversation_config": {},
        "label": "Success A"
      },
      "success_end": {},
      "success_phone": {
        "transfer_destination": {
          "phone_number": "\u002B1234567890"
        }
      },
      "success_transfer": {
        "agent_id": "success_transfer_agent"
      },
      "tool_node_a": {
        "edge_order": [
          "tool_a_to_failure",
          "tool_a_to_tool_b"
        ],
        "tools": [
          {
            "tool_id": "tool_a"
          },
          {
            "tool_id": "tool_b"
          }
        ]
      },
      "tool_node_b": {
        "edge_order": [
          "tool_b_to_conversation",
          "tool_b_to_end",
          "tool_b_to_phone",
          "tool_b_to_agent_transfer"
        ],
        "tools": [
          {
            "tool_id": "tool_a"
          }
        ]
      }
    }
  },
  "name": "string",
  "tags": [
    "string"
  ]
}

